```class Solution {
public:
    int minimizedStringLength(string s) {
        int n = s.size();
        int i = 0, j = n - 1;
        while (i < j) {
            if (s[i] == s[j]) {
                i++;
                j--;
            } else if (s[i + 1] == s[j]) {
                i++;
            } else {
                j--;
            }
        }
        return j - i + 1;
    }
};
